B.E3=new A.u("Hidracija","Pojacani unos tecnosti, mokra hrana ili dodavanje vode suvoj hrani","Nadoknada tecnosti izgubljenih povracanjem i dijarejom.")
B.CT=new A.u("Vitamini A, C, E","Dodaci ili hrana bogata antioksidansima","Jacanje imunog odgovora i zastita celija od oksidativnog stresa.")
B.Kj=A.a(s([B.Dw,B.E3,B.CT]),t.x)
