B.La=A.a(s(["Sirova hrana","Masna hrana","Mlecni proizvodi","Zacini","Kosti"]),t.s)
B.Sj=new A.ae("Stajemper (Distemper)","Stajemper je teska virusna bolest pasa izazvana Canine Distemper Virusom (CDV) iz porodice Paramyxoviridae koja napada respiratorni, gastrointestinalni i nervni sistem. Virus se siri kapljicnim putem i kontaktom sa zarazenim sekretima, a mortalitet kod nevakcinisanih stenaca moze dostici 80%. Preboleli psi cesto zadrze trajne neuroloske posledice poput tikova, pareze i hipoplazije zubne gledjii.",B.b9,"\ud83e\udda0",B.O2,B.Kj,B.Ib,B.La,"Ne postoji specificni antivirusni lek za stajemper \u2014 lecenje je iskljucivo suportivno. Primenjuju se intravenski infuzioni rastvori (Ringerov laktat, fizioloski rastvor) za korekciju dehidracije. Antibiotici sirokospektralnog dejstva poput Amoksicilina sa klavulanskom kiselinom ili Cefaleksina koriste se za prevenciju sekundarnih bakterijskih infekcija. Antiemetici kao sto je Maropitant (Cerenia) kontrolisu povracanje, dok se Metoklopramid koristi za regulaciju motiliteta. Za kontrolu konvulzija primenjuje se Diazepam ili Fenobarbital. Vitamin B kompleks i vitamin C daju se kao podrska oporavku. Vakcinacija (DHPPi vakcina) je jedina pouzdana prevencija bolesti.")
B.JE=A.a(s(["Profuzna krvava dijareja","Jako povracanje","Visoka temperatura pra\u0107ena hipotermijom","Teska dehidracija","Letargija i depresija","Gubitak apetita (anoreksija)","Bolovi u abdomenu","Brzi gubitak telesne mase"]),t.s)
B.DW=new A.u("Hidracija","Intravenska rehidracija, zatim postepeno uvodjenje vode i elektrolita oralno","Kriticna nadoknada tecnosti i elektrolita izgubljenih masivnom dijarejom i povracanjem.")
B.Eq=new A.u("Proteini","Lako svarljivi proteini u malim, cestim obrocima nakon prestanka povracanja","Obnova ostecenog crevnog epitela zahteva aminokiseline, posebno glutamin.")
B.CJ=new A.u("Probiotici","Veterinarski probiotici nakon akutne faze","Obnova crevne mikroflore unistene virusom i antibioticima.")
B.Mn=A.a(s([B.DW,B.Eq,B.CJ]),t.x)
B.Nm=A.a(s(["Kuvana piletina","Pirinac","Probiotici","Glutamin","Elektroliti","Bundeva"]),t.s)
B.O6=A.a(s(["Masna hrana","Sirova hrana","Mleko","Tesko svarljiva hrana","Kosti"]),t.s)
B.RS=new A.ae("Parvoviroza","Parvoviroza je akutna, visoko kontagiozna virusna bolest pasa izazvana Canine Parvovirusom tip 2 (CPV-2) koji napada brzo delece celije crevnog epitela i kostne srzi. Bolest je narocito opasna za nevakcinisane stenade uzrasta 6 nedelja do 6 meseci, sa mortalitetom do 90% bez lecenja. Virus je izuzetno otporan u spoljasnjoj sredini i moze preziveti mesecima na kontaminiranim povrsinama.",B.b9,"\ud83e\udda0",B.JE,B.Mn,B.Nm,B.O6,"Lecenje parvoviruze je intenzivno suportivno jer ne postoji antivirusni lek. Agresivna intravenska fluidna terapija Ringerovim laktatom sa suplementacijom kalijuma (KCl) je osnova lecenja. Antiemetici Maropitant (Cerenia) i Ondansetron primenjuju se za kontrolu povracanja. Antibiotici sirokospektralnog dejstva \u2014 Ampicilin sa Sulbaktamom ili kombinacija Metronidazola i Ceftriaksona \u2014 sprecavaju sepsu usled translokacije bakterija kroz ostecenu crevnu barijeru. U teskim slucajevima primenjuje se Oseltamivir (Tamiflu) kao adjuvantna terapija. Transfuzija plazme ili primena hiperimunog seruma moze poboljsati ishod. Analgetici poput Buprenorfina koriste se za kontrolu abdominalnog bola.")
B.KP=A.a(s(["Hromost koja menja nogu (seljiva hromost)","Oteceni i bolni zglobovi","Povisen temperatura","Letargija i malaksalost","Gubitak apetita","Uvecani limfni cvorovi","Ukocen hod","Osetljivost na dodir"]),t.s)
B.Fz=new A.u("Omega-3 masne kiseline","Riblje ulje ili laneno ulje svakodnevno","Smanjenje upale u zglobovima i podrska bubreznoj funkciji.")
B.Db=new A.u("Proteini","Umereni, visokokvalitetni proteini; smanjiti ako su bubrezi pogodeni","Podrska imunom sistemu uz zastitu bubrega od preopterecenja.")
B.EF=new A.u("Antioksidansi","Hrana bogata vitaminom E, selenom i kurkuminom","Zastita tkiva od oksidativnog ostecenja uzrokovanog hronicnom upalom.")
B.Mu=A.a(s([B.Fz,B.Db,B.EF]),t.x)
B.Js=A.a(s(["Losos","Riblje ulje","Borovnice","Brokoli","Kurkuma","Slatki krompir"]),t.s)
B.Kc=A.a(s(["Hrana bogata natrijumom","Preradeviine","Vestacki aditivi","Psenica","Kukuruz"]),t.s)
B.RZ=new A.ae("Lajmska bolest","Lajmska bolest (borellioza) je multisistemska bakterijska infekcija izazvana spiralnom bakterijom Borrelia burgdorferi koju prenose krpelji roda Ixodes. Bolest pogadja zglobove, bubrege, srce i nervni sistem, a simptomi se mogu pojaviti nedeljama ili mesecima nakon ujeda krpelja. Bez lecenja moze dovesti do hronicnog artritisa, glomerulonefritisa i fatalnog bubreznog otkazivanja (Lajmski nefritis).",B.b9,"\ud83e\udeb2",B.KP,B.Mu,B.Js,B.Kc,"Antibiotik prvog izbora za Lajmsku bolest je Doksiciklin u dozi od 10 mg/kg oralno svakih 12 sati tokom 30 dana. Alternativno se koristi Amoksicilin u dozi od 20 mg/kg svakih 8 sati ako pas ne tolerise Doksiciklin. Za kontrolu bola i upale u zglobovima primenjuju se nesteroidni antiinflamatorni lekovi (NSAIL) poput Meloksikama ili Karprofen. U slucaju Lajmskog nefritisa dodaje se imunosupresivna terapija Mikofenolat-mofetilom i ACE inhibitor Enalapril za zastitu bubrega. Prevencija ukljucuje redovnu primenu antiparazitika (Fluralaner \u2014 Bravecto, ili Sarolaner \u2014 Simparica) i vakcinaciju protiv borelioze.")
B.LW=A.a(s(["Hronicni kasalj","Netolerancija napora","Gubitak daha nakon aktivnosti","Gubitak telesne mase","Distenzija abdomena (ascites)","Letargija","Kolaps nakon napora","Bledilo sluznica"]),t.s)
B.CC=new A.u("Proteini","Umereni visokokvalitetni proteini za odrzavanje misicne mase","Sprecavanje kaheksije bez preopterecenja srcano-plucnog sistema.")
B.CI=new A.u("Natrijum","Nizak unos natrijuma","Smanjenje retencije tecnosti i opterecenja srca.")
B.Ea=new A.u("Taurin i L-karnitin","Suplementacija ili hrana bogata ovim aminokiselinama","Podrska funkciji srcnog misica i energetskom metabolizmu miokarda.")
B.DC=new A.u("Omega-3","Riblje ulje kao izvor EPA i DHA","Smanjenje upale u plucnim arterijama i podrska kardiovaskularnom zdravlju.")
B.NA=A.a(s([B.CC,B.CI,B.Ea,B.DC]),t.x)
B.MC=A.a(s(["Losos","Curetina","Riblje ulje","Taurin","L-karnitin","Bundeva"]),t.s)
B.Lr=A.a(s(["Slana hrana","Preradeviine","Masna hrana","Hrana sa visokim natrijumom","Kosti"]),t.s)
B.Sk=new A.ae("Srcani crv (Dirofilarioza)","Dirofilarioza je parazitska bolest izazvana nematodom Dirofilaria immitis cije odrasle forme zive u plucnim arterijama i desnom srcu psa. Komarci su vektori koji prenose larvene stadijume (mikrofilarije) sa zarazenog na zdravog psa. Nelecena bolest dovodi do plucne hipertenzije, kongestivne srcane insuficijencije i sindroma vene kave koji je fatalan.",B.b9,"\ud83e\udeb1",B.LW,B.NA,B.MC,B.Lr,"Adultocidna terapija podrazumeva intramuskularnu primenu Melarsomin dihidrohlorida (Immiticide) po protokolu od tri injekcije \u2014 prva doza, zatim mesec dana pauze, pa dve doze u razmaku od 24 sata. Pre adultocidne terapije daje se Doksiciklin 10 mg/kg dva puta dnevno tokom 4 nedelje za eliminaciju Wolbachia endosimbionta. Mesecna preventiva Ivermektinom ili Moksidektinom eliminise mikrofilarije i sprecava nove infekcije. Prednizolon se daje za smanjenje upalne reakcije na uginule parazite. Strogi mirovanje tokom 6-8 nedelja nakon terapije je obavezan da bi se sprecila plucna tromboembolija. U teskim slucajevima sa sindromom vene kave, hirurska ekstrakcija crva kroz jugularnu venu je jedina opcija.")
B.IF=A.a(s(["Neproduktivno povracanje (bezuspesni pokusaji)","Naglo naduvavanje abdomena","Nemir i nemogucnost nalazenja polozaja","Prekomerno linjenje sline","Ubrzan rad srca (tahikardija)","Bledilo desni","Slabost i kolaps","Bolnost pri palpaciji abdomena"]),t.s)
B.Dg=new A.u("Velicina obroka","Vise manjih obroka dnevno (3-4) umesto jednog velikog","Smanjenje rizika od prekomerne distenzije zeluca.")
B.Ct=new A.u("Brzina hranjenja","Koristiti anti-gutanje ciniju ili puzzle feeder","Sprecavanje aerofagije (gutanja vazduha) koja doprinosi dilataciji.")
