B.RU=new A.ae("Dermatofitoza (Lishaj)","Dermatofitoza je gljivicna infekcija koze, dlake i kandzi izazvana dermatofitima, najcesce Microsporum canis (odgovoran za 90% slucajeva kod macaka i 70% kod pasa). Bolest je visoko kontagiozna i predstavlja znacajnu zoonozu \u2014 lako se prenosi na ljude, narocito decu i imunosuprimovane osobe. Spore gljivica mogu preziveti u okruzenju do 18 meseci, sto otezava eradikaciju.",B.aa,"\ud83c\udf44",B.I5,B.Jb,B.Nd,B.I8,"Sistemska antimikotska terapija je obavezna \u2014 Itrakonazol je lek prvog izbora u dozi od 5 mg/kg dnevno u pulsnom protokolu (nedelju dana terapije, nedelju pauze) tokom 6-8 nedelja. Terbinafin (30-40 mg/kg dnevno) je alternativa sa odlicnom efikasnoscu. Grizeofulvin (25-50 mg/kg dnevno) je stariji lek koji se jos koristi, ali je kontraindikovan kod gravidnih zivotinja i macaka sa FIV-om. Lokalna terapija ukljucuje kupanje u rastvoru Enilkonazola (Imaverol) ili Lime Sulfur (kalcijum polisulfid) dva puta nedeljno. Mikonazol/Hlorheksidin sampon koristi se za redukciju spora na dlaci. Dekontaminacija okruzenja rastvorom natrijum-hipohlorita (1:10) je kriticna za sprecavanje reinfekcije. Kontrolne gljivicne kulture rade se svakih 2-3 nedelje do dva uzastopna negativna nalaza.")
B.K2=A.a(s(["Cesanje i trljanje usiju","Tresenje glavom","Neprijatan miris iz usiju","Crvenilo i otok usnog kanala","Tamni ili gnojan iscedak iz uha","Bol pri dodiru usiju","Naginjanje glave na stranu","Gubitak sluha (u teskim slucajevima)"]),t.s)
B.DD=new A.u("Omega-3 masne kiseline","Riblje ulje svakodnevno","Smanjenje alergijske upale koja je najcesci osnovni uzrok otitisa.")
B.Dp=new A.u("Eliminaciona dijeta","Probna dijeta sa novim proteinom ako se sumnja na alergiju na hranu","Alergija na hranu je cest uzrok rekurentnog otitisa.")
B.DO=new A.u("Probiotici","Veterinarski probiotici za podrsku imunom sistemu","Modulacija imunog odgovora i smanjenje sklonosti ka alergijskim reakcijama.")
