B.Jy=A.a(s(["Lubenica (bez semenki)","Krastavac","Mokra hrana","Elektroliti","Bundeva","Borovnice"]),t.s)
B.O3=A.a(s(["Slana hrana","Suva hrana bez dodatne vode","Masna hrana","Cokolada","Alkohol"]),t.s)
B.S9=new A.ae("Toplotni udar","Toplotni udar (hipertermija) je zivotno ugrozavajuce stanje u kome telesna temperatura prelazi 41\xb0C usled nemogucnosti organizma da se adekvatno ohladi. Psi su posebno podlozni jer se hlade iskljucivo dahtanjem, a brahicefalicne rase (mops, engleski buldog, francuski buldog), gojazne i starije zivotinje su u najvecem riziku. Teska hipertermija dovodi do diseminovane intravaskularne koagulacije (DIK), otkazivanja organa i smrti.",B.aa,"\ud83c\udf21\ufe0f",B.Ky,B.Ly,B.Jy,B.O3,"Toplotni udar je hitno stanje koje zahteva momentalno hladjenje \u2014 vlazenje krzna mlakom (ne hladnom) vodom i ventilator za evaporativno hladjenje. Agresivna intravenska fluidna terapija hladnim kristaloidima (Ringerov laktat) je kriticna za stabilizaciju cirkulacije. Temperatura se prati rektalno svakih 5 minuta i hladjenje se prekida na 39.5\xb0C da bi se sprecila hipotermija. Maropitant (Cerenia) primenjuje se za kontrolu povracanja, a Metoklopramid za gastroparezu. Sveza smrznuta plazma ili transfuzija pune krvi daje se kod razvoja DIK-a (diseminovane intravaskularne koagulacije). Manitol ili Furosemid koriste se za prevenciju akutnog otkazivanja bubrega. Antibiotici sirokospektralnog dejstva (Ampicilin sa Sulbaktamom) primenjuju se profilakticki zbog translokacije bakterija iz ostecenih creva. Intenzivni monitoring ukljucuje pracenje koagulacionog statusa, bubreznih parametara i hepatickih enzima tokom 48-72 sata.")
B.JU=A.a(s([B.Sj,B.RS,B.RZ,B.Sk,B.Rp,B.Sm,B.S8,B.Sf,B.Rv,B.Rj,B.RF,B.RB,B.Rx,B.RO,B.RK,B.RP,B.RU,B.RW,B.S4,B.S9]),t.g5)
