B.J9=A.a(s(["psenica","kukuruz","soja","govedina","mlecni proizvodi","vestacki dodaci"]),t.s)
B.Rr=new A.ae("Alergije na hranu","Alergija na hranu je imunoloski posredovana reakcija preosetljivosti na odredjene proteine u hrani, najcesce govedinu, piletinu, mlecne proizvode, psenicu ili soju. Razlikuje se od intolerancije na hranu koja ne ukljucuje imuni sistem. Dijagnoza se postavlja eliminacionom dijetom u trajanju od 8-12 nedelja sa novim izvorom proteina koji zivotinja ranije nije jela.",B.aa,"\ud83e\udd27",B.LB,B.Jm,B.Ia,B.J9,"Lecenje alergija na hranu pocinje strogom eliminacionom dijetom sa hidrolizovanim proteinima ili potpuno novim izvorom proteina u trajanju od minimum 8 nedelja. Oclacitinib (Apoquel) se koristi za brzo smanjenje svraba kod pasa, dok se Lokivetmab (Cytopoint) daje kao mesecna injekcija za dugotrajnu kontrolu. Kod macaka se mogu koristiti antihistaminici poput Cetirizina ili kratki kursevi kortikosteroida (Prednizolon). Sekundarne kozne infekcije se lece antibioticima (Cefaleksin) ili antifungalnim samponiima sa Hlorheksidinom. Esencijalne masne kiseline (omega-3) pomazu u jacanju kozne barijere i smanjenju upale. Posle eliminacione dijete, provokacioni test sa pojedinacnim namirnicama identifikuje tacne alergene. Obavezno posetite veterinarskog dermatologa za alergijsko testiranje i dugorocni plan ishrane.")
B.MY=A.a(s(["Vidljiv visak kilograma","Tesko disanje pri naporu","Smanjena aktivnost","Otezano kretanje","Ne mogu se napipati rebra","Brzo zamaranje","Hramanje (opterecenje zglobova)"]),t.s)
B.DJ=new A.u("Kalorije","low","Smanjen kalorijski unos za gubitak tezine.")
B.Fl=new A.u("Vlakna","high","Vlakna daju osecaj sitosti.")
B.Ej=new A.u("Proteini","high","Visok protein cuva misicnu masu tokom mrsavljenja.")
B.LR=A.a(s([B.DJ,B.Fl,B.Ej]),t.x)
