B.nd=A.a(s(["mast","secer","kukuruzni sirup","nusproizvod"]),t.s)
B.S3=new A.ae("Gojaznost","Gojaznost je stanje prekomerne telesne mase koje nastaje kada energetski unos hronicno prevazilazi potrosnju, sto dovodi do nakupljanja masnog tkiva. Smatra se da je zivotinja gojazna kada prelazi 20% idealne telesne mase. Gojaznost je faktor rizika za dijabetes, artritis, srcane bolesti, hepaticku lipidozu i skracen zivotni vek.",B.aa,"\u2696\ufe0f",B.MY,B.LR,B.np,B.nd,"Lecenje gojaznosti zahteva kombinaciju dijetetskog rezima i povecane fizicke aktivnosti pod nadzorom veterinara. Cilj je postepeni gubitak tezine od 1-2% nedeljno \u2014 brze mrsavljenje moze izazvati hepaticku lipidozu, narocito kod macaka. Preporucuje se prelazak na niskokalorijske dijetetske formule sa visokim sadrzajem proteina i vlakana. Dnevni obrok se deli na 3-4 manja obroka da se odrzava metabolizam i smanjuje osecaj gladi. L-karnitin kao suplement pomaze u sagorevanju masti i ocuvanju misicne mase. Kod pasa sa hipotireozom kao uzrokom gojaznosti, potrebna je suplementacija tiroksinom (Levotiroksin). Redovno merenje telesne mase i ocene telesne kondicije (BCS) kod veterinara su neophodni za pracenje napretka.")
B.KK=A.a(s(["Bolno mokrenje","Krv u mokraci","Ucestalo mokrenje u malim kolicinama","Mokrenje van posude/napolju","Lizanje genitalnog podrucja","Naprezanje pri mokrenju","Nemogucnost mokrenja (hitno!)"]),t.s)
B.D1=new A.u("Magnezijum","low","Visak magnezijuma doprinosi formiranju kristala.")
B.D8=new A.u("Fosfor","low","Kontrola fosfora smanjuje rizik od kamenaca.")
B.EO=new A.u("Vlaga","high","Mokra hrana pomaze razblazienju urina.")
B.JT=A.a(s([B.D1,B.D8,B.EO]),t.x)
B.NC=A.a(s(["piletina","riba","vlazna hrana","brusnica"]),t.s)
B.N3=A.a(s(["magnezijum","pepeo","fosfor","so"]),t.s)
B.Ry=new A.ae("Urinarni problemi","Urinarni problemi obuhvataju formiranje kristala i kamenaca (urolitijazu) u mokracnoj besici ili uretri, kao i idiopatski cistitis kod macaka (FIC). Najcesci tipovi kamenaca su struvitni (magnezijum-amonijum-fosfat) i kalcijum-oksalatni. Opstrukcija uretre je hitno stanje koje moze dovesti do akutnog otkazivanja bubrega i smrti u roku od 24-48 sati.",B.aa,"\ud83d\udca7",B.KK,B.JT,B.NC,B.N3,"Lecenje zavisi od tipa kamenaca i prisustva opstrukcije. Kod opstrukcije uretre potrebna je hitna kateterizacija pod sedacijom i ispiranje mokracne besike. Struvitni kamenci se mogu rastvoriti specijalnom dijetetskom hranom koja zakiseljava urin (pH ispod 6.5), dok kalcijum-oksalatni kamenci zahtevaju hirursko uklanjanje (cistotomija). Antibiotici poput Amoksicilina sa klavulanskom kiselinom se daju kod bakterijskih infekcija urinarnog trakta. Prazosin se koristi za relaksaciju uretre kod macaka sa ponavljajucim opstrukcijama. Kod idiopatskog cistitisa macaka, smanjenje stresa, Feliway difuzeri i suplementi poput glukozaminoglikana (GAG) pomazu u kontroli simptoma. Obavezno posetite veterinara za analizu urina, ultrazvuk i rendgen mokracne besike radi identifikacije tipa kristala.")
B.Ie=A.a(s(["Kasalj (narocito nocu)","Tesko disanje","Brzo zamaranje","Smanjena aktivnost","Gubitak apetita","Nadut stomak (tecnost)","Plavicaste desni","Nesvestica"]),t.s)
B.Fa=new A.u("Natrijum","low","Nizak natrijum smanjuje zadrzavanje tecnosti.")
B.ED=new A.u("Taurin","high","Taurin je kljucan za funkciju srcanog misica.")
B.EN=new A.u("Omega-3","high","Smanjuje upalu i podrzava srce.")
B.Mw=A.a(s([B.Fa,B.ED,B.EN]),t.x)
B.HZ=A.a(s(["riba","losos","taurin","omega 3","riblje ulje","piletina"]),t.s)
B.LT=A.a(s(["so","natrijum","slanina","preradjeno meso"]),t.s)
B.Sl=new A.ae("Srcana bolest","Srcane bolesti kod pasa i macaka obuhvataju degenerativnu bolest mitralnog zaliska (MMVD, najcesca kod pasa malih rasa), dilatativnu kardiomiopatiju (DCM, kod velikih rasa) i hipertroficnu kardiomiopatiju (HCM, najcesca kod macaka). Bolest dovodi do smanjene sposobnosti srca da pumpa krv, nakupljanja tecnosti u plucima ili abdomenu i progresivnog otkazivanja srca.",B.aa,"\u2764\ufe0f",B.Ie,B.Mw,B.HZ,B.LT,"Lecenje srcane bolesti zavisi od stadijuma i tipa oboljenja. Pimobendan (Vetmedin) je lek prvog izbora kod pasa sa MMVD i DCM jer poboljsava kontraktilnost srca i sirii krvne sudove. Furosemid (Lasix) je diuretik koji se koristi za uklanjanje viska tecnosti iz pluca i abdomena. ACE inhibitori poput Enalaprila ili Benazeprila smanjuju opterecenje srca i usporavaju progresiju bolesti. Spironolakton se dodaje kao blagi diuretik i antifibrotik. Kod macaka sa HCM, Atenolol ili Diltiazem se koriste za usporavanje srcane frekvencije, a Klopidogrel za prevenciju tromboembolije. Suplementacija taurinom je obavezna kod DCM povezane sa deficitom taurina. Redovni ultrazvucni pregledi srca (ehokardiografija) kod veterinarskog kardiologa su neophodni za pracenje napredovanja bolesti.")
B.J1=A.a(s(["Hramanje","Ukocenost posle odmora","Otezano ustajanje","Smanjena aktivnost","Bolni zglobovi na dodir","Oteceni zglobovi","Lizanje bolnih mesta","Odbijanje skakanja ili penjanja"]),t.s)
B.E9=new A.u("Omega-3","high","Snazno antiinflamatorno dejstvo na zglobove.")
B.D4=new A.u("Glukozamin","high","Podrzava obnovu hrskavice.")
B.CP=new A.u("Kalorije","low","Odrzavanje idealne tezine smanjuje opterecenje zglobova.")
B.NM=A.a(s([B.E9,B.D4,B.CP]),t.x)
B.JL=A.a(s(["losos","riblje ulje","omega 3","glukozamin","hondroitin","kurkuma"]),t.s)
B.Ny=A.a(s(["secer","kukuruz","psenica","nusproizvod"]),t.s)
B.S6=new A.ae("Artritis","Osteoartritis je degenerativna bolest zglobova koja nastaje usled propadanja zglobne hrskavice, sto dovodi do bola, upale i smanjene pokretljivosti. Najcesce pogadja kukove, kolena, laktove i kicmu, narocito kod starijih i gojaznih zivotinja. Bolest je progresivna i neizleciva, ali se simptomi mogu znacajno kontrolisati kombinacijom dijete, lekova i fizikalne terapije.",B.aa,"\ud83e\uddb4",B.J1,B.NM,B.JL,B.Ny,"Nesteroidni antiinflamatorni lekovi (NSAIL) poput Meloksikama (Metacam) ili Karprofen (Rimadyl) su osnova terapije bola kod pasa, dok se kod macaka koristi Meloksikam u nizoj dozi ili noviji lek Solensia (Frunevetmab, anti-NGF antitelo). Glukozamin-hondroitin sulfat suplementi pomazu u zastiti i obnovi hrskavice. Adekvan (polisulfatovani glikozaminoglikan) se daje kao serija injekcija za zastitu zglobne hrskavice. Omega-3 masne kiseline u visokim dozama (EPA i DHA) imaju dokazano antiinflamatorno dejstvo. Fizikalna terapija ukljucujuci hidroterapiju, lasersku terapiju i kontrolisane setnje znacajno poboljsava pokretljivost. Odrzavanje idealne telesne mase je kljucno jer svaki visak kilograma dodatno opterecuje zglobove. Obavezno posetite veterinara za rendgen zglobova i plan lecenja prilagodjen stadijumu bolesti.")
B.N_=A.a(s(["Hronican proliv","Povracanje","Gubitak tezine","Gubitak apetita","Krv ili sluz u stolici","Nadimanje i gasovi","Bolovi u stomaku","Lose stanje dlake"]),t.s)
B.DU=new A.u("Proteini","moderate","Hidrolizovani ili novi proteini smanjuju reakciju creva.")
B.DI=new A.u("Masti","low","Niske masti su lakse za varenje.")
B.mg=new A.u("Probiotici","high","Podrzavaju zdravu crevnu floru.")
B.N8=A.a(s([B.DU,B.DI,B.mg]),t.x)
B.NE=A.a(s(["piletina","curetina","pirinac","bundeva","probiotici","prebiotici"]),t.s)
B.Og=A.a(s(["psenica","kukuruz","soja","mlecni proizvodi","vestacki dodaci"]),t.s)
B.Rw=new A.ae("Upalna bolest creva (IBD)","Upalna bolest creva (IBD) je hronicno stanje karakterisano infiltracijom zapaljenskih celija u zid creva, sto dovodi do poremecaja varenja i apsorpcije hranljivih materija. Najcesci oblici su limfocitno-plazmocitni enteritis i eozinofilni enteritis. Dijagnoza se postavlja biopsijom creva, a lecenje zahteva kombinaciju dijetetske terapije i imunosupresivnih lekova.",B.aa,"\ud83e\ude7a",B.N_,B.N8,B.NE,B.Og,"Lecenje IBD-a zahteva kombinaciju dijetetske i medikamentozne terapije. Prednizolon je imunosupresivni lek prvog izbora koji se daje u opadajucim dozama tokom nekoliko nedelja. Budezonid se koristi kao alternativa sa manje sistemskih nuspojava jer deluje lokalno na creva. Metronidazol ima antiinflamatorno i antibakterijsko dejstvo na creva i cesto se kombinuje sa kortikosteroidima. Kod teskih slucajeva koji ne reaguju na steroide, koriste se jaci imunosupresivi poput Azatioprina (kod pasa) ili Hlorambucila (kod macaka). Dijeta sa hidrolizovanim proteinima ili novim izvorom proteina je kljucna za smanjenje antigenske stimulacije creva. Probiotici i prebiotici pomazu u obnovi zdrave crevne mikroflore. Redovne kontrole kod veterinara sa krvnim analizama su neophodne za pracenje nuspojava lekova i prilagodjavanje terapije.")
B.Jh=A.a(s(["Debljanje bez povecanog apetita","Letargija i pospanost","Gubitak dlake","Suva i ljuspasta koza","Osetljivost na hladnocu","Spor puls","Tamna pigmentacija koze","Ceste kozne infekcije"]),t.s)
