B.KU=A.a(s(["timotejka seno","livadsko seno","lisnato povrce","grancice vrbe ili jabuke","celjer"]),t.s)
B.NG=A.a(s(["meka hrana","pelet kao jedina hrana","secer","zitarice","hleb"]),t.s)
B.Sh=new A.ae("Malokluzija zuba","Malokluzija (nepravilan zagrizam) i prerastanje zuba je cest problem kod kunica jer njihovi zubi rastu kontinuirano tokom celog zivota brzinom od 2-3 mm nedeljno. Ako zubi nisu pravilno poravnati ili kunic ne dobija dovoljno sena za prirodno habanje, zubi prerastaju i formiraju ostre ivice (spikule) koje povredjuju jezik, obraze i desni. Bolest moze zahvatiti i sekutice i kutnjake, a nelecena dovodi do apscesa vilice i nemogucnosti hranjenja.",B.eb,"\ud83e\uddb7",B.LC,B.LU,B.KU,B.NG,"Lecenje malokluzije zahteva redovno skracivanje i turpijanje zuba kod veterinara pod sedacijom ili opstom anestezijom. Prerasle sekutice se skracuju dijamantskim diskom ili zubnom busilom \u2014 nikada klestima jer to moze izazvati frakturu zuba. Spikule na kutnjacima se uklanjaju specijalnim zubarskim instrumentima uz pomoc otoskopa ili endoskopa za vizualizaciju. Apscesi vilice zahtevaju hirursko otvaranje, kiretazu i dugotrajnu antibiotsku terapiju Enrofloksacinom ili Penicilin G injekcijama. Meloksikam se daje za kontrolu bola pre i posle zahvata. Prisilno hranjenje kasastom hranom (Critical Care) je neophodno dok se kunic ne oporavi dovoljno da sam jede. Neogranicen pristup kvalitetnom senu je najvaznija preventivna mera jer zvakanje sena prirodno haba zube. Obavezno posetite veterinara specijalistu za egzoticne zivotinje za rendgen lobanje radi procene korena zuba i kostiju vilice.")
B.ND=A.a(s(["Naginjanje glave na jednu stranu","Gubitak ravnoteze","Kotrljanje (rolling)","Nistagmus (brzo pomeranje ociju)","Slabost zadnjih nogu","Inkontinencija urina","Belo zamucenje u oku (katarakta)","Gubitak apetita"]),t.s)
